     1→/**
     2→ * Shared UI components used across pages.
     3→ * FilterDatePicker — range date picker (portal, same style as in LeadList)
     4→ * SingleDatePicker — single-date picker (portal)
     5→ * PortalSelect     — custom portal dropdown (replaces native <select>)
     6→ */
     7→import React, { useState, useEffect, useRef } from 'react';
     8→import { createPortal } from 'react-dom';
     9→import { CalendarDays, ChevronDown, ChevronLeft, ChevronRight, Check } from 'lucide-react';
    10→
    11→const MONTHS_RU    = ['Январь','Февраль','Март','Апрель','Май','Июнь','Июль','Август','Сентябрь','Октябрь','Ноябрь','Декабрь'];
    12→const MONTHS_SHORT = ['янв','фев','мар','апр','май','июн','июл','авг','сен','окт','ноя','дек'];
    13→const DAYS_SHORT   = ['Пн','Вт','Ср','Чт','Пт','Сб','Вс'];
    14→
    15→export function parseDateStr(str: string): Date | null {
    16→  if (!str) return null;
    17→  const s = String(str).slice(0, 10);
    18→  const [y, m, d] = s.split('-').map(Number);
    19→  if (!y || !m || !d) return null;
    20→  return new Date(y, m - 1, d);
    21→}
    22→export function toDateStr(d: Date): string {
    23→  return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
    24→}
    25→export function todayLocal(): string {
    26→  return new Date().toLocaleDateString('sv');
    27→}
    28→function fmtDateShort(str: string): string {
    29→  const d = parseDateStr(str);
    30→  if (!d) return '—';
    31→  return `${String(d.getDate()).padStart(2,'0')} ${MONTHS_SHORT[d.getMonth()]} ${d.getFullYear()}`;
    32→}
    33→
    34→function buildCells(year: number, month: number): (number | null)[] {
    35→  const firstDay = new Date(year, month, 1);
    36→  const lastDay  = new Date(year, month + 1, 0);
    37→  let startDow = firstDay.getDay() - 1;
    38→  if (startDow < 0) startDow = 6;
    39→  const cells: (number | null)[] = [];
    40→  for (let i = 0; i < startDow; i++) cells.push(null);
    41→  for (let d = 1; d <= lastDay.getDate(); d++) cells.push(d);
    42→  while (cells.length % 7 !== 0) cells.push(null);
    43→  return cells;
    44→}
    45→
    46→/* ══════════════════════════════════════════════
    47→   FilterDatePicker — range picker with portal
    48→══════════════════════════════════════════════ */
    49→export function FilterDatePicker({
    50→  valueFrom, valueTo, onChange, label,
    51→}: {
    52→  valueFrom: string;
    53→  valueTo: string;
    54→  onChange: (from: string, to: string) => void;
    55→  label: string;
    56→}) {
    57→  const [open, setOpen]           = useState(false);
    58→  const [selecting, setSelecting] = useState<string | null>(null);
    59→  const [hoverDate, setHoverDate] = useState<string | null>(null);
    60→  const btnRef  = useRef<HTMLButtonElement>(null);
    61→  const dropRef = useRef<HTMLDivElement>(null);
    62→  const [pos, setPos]             = useState({ top: 0, left: 0 });
    63→  const today = todayLocal();
    64→
    65→  const initDate = parseDateStr(valueFrom) || new Date();
    66→  const [viewYear,  setViewYear]  = useState(initDate.getFullYear());
    67→  const [viewMonth, setViewMonth] = useState(initDate.getMonth());
    68→
    69→  const updatePos = () => {
    70→    if (btnRef.current) {
    71→      const r = btnRef.current.getBoundingClientRect();
    72→      setPos({ top: r.bottom + 8, left: r.left });
    73→    }
    74→  };
    75→
    76→  const handleOpen = () => {
    77→    if (!open) { updatePos(); setSelecting(null); setHoverDate(null); }
    78→    setOpen(o => !o);
    79→  };
    80→  const handleClose = () => { setOpen(false); setSelecting(null); setHoverDate(null); };
    81→
    82→  useEffect(() => {
    83→    if (!open) return;
    84→    function onDown(e: MouseEvent) {
    85→      const t = e.target as Node;
    86→      if (btnRef.current && !btnRef.current.contains(t) && dropRef.current && !dropRef.current.contains(t)) handleClose();
    87→    }
    88→    function onScroll() { updatePos(); }
    89→    document.addEventListener('mousedown', onDown);
    90→    window.addEventListener('scroll', onScroll, true);
    91→    return () => { document.removeEventListener('mousedown', onDown); window.removeEventListener('scroll', onScroll, true); };
    92→  }, [open]);
    93→
    94→  function prevMonth() { if (viewMonth === 0) { setViewMonth(11); setViewYear(y => y-1); } else setViewMonth(m => m-1); }
    95→  function nextMonth() { if (viewMonth === 11) { setViewMonth(0); setViewYear(y => y+1); } else setViewMonth(m => m+1); }
    96→
    97→  const handleDayClick = (dateStr: string) => {
    98→    if (!selecting) {
    99→      setSelecting(dateStr);
   100→    } else {
   101→      const from = selecting < dateStr ? selecting : dateStr;
   102→      const to   = selecting < dateStr ? dateStr : selecting;
   103→      onChange(from, to);
   104→      setSelecting(null); setHoverDate(null); setOpen(false);
   105→    }
   106→  };
   107→
   108→  const rangeFrom  = selecting || valueFrom;
   109→  const rangeTo    = selecting ? (hoverDate || '') : valueTo;
   110→  const isActive   = !!(valueFrom || valueTo);
   111→  const cells      = buildCells(viewYear, viewMonth);
   112→
   113→  const displayLabel = (() => {
   114→    if (selecting) return `${fmtDateShort(selecting)} →`;
   115→    if (!valueFrom) return 'Все';
   116→    if (!valueTo || valueFrom === valueTo) return fmtDateShort(valueFrom);
   117→    return `${fmtDateShort(valueFrom)} — ${fmtDateShort(valueTo)}`;
   118→  })();
   119→
   120→  return (
   121→    <div className="relative flex items-center">
   122→      <button
   123→        ref={btnRef} type="button" onClick={handleOpen}
   124→        className={`text-xs pl-3 pr-7 py-2 border rounded-xl focus:outline-hidden cursor-pointer shadow-3xs transition-all duration-150 flex items-center gap-1.5 whitespace-nowrap ${
   125→          isActive ? 'bg-neutral-950 text-white border-neutral-950' : 'bg-white/60 hover:bg-white border-neutral-200/70 text-neutral-700'
   126→        }`}
   127→      >
   128→        <CalendarDays className={`w-3 h-3 shrink-0 ${isActive ? 'text-white/70' : 'text-neutral-400'}`} />
   129→        <span className={`font-medium ${isActive ? 'text-white/70' : 'text-neutral-400'}`}>{label}</span>
   130→        <span className={isActive ? 'text-white/40' : 'text-neutral-300'}>·</span>
   131→        <span className="font-bold">{displayLabel}</span>
   132→      </button>
   133→      <ChevronDown className={`absolute right-2 w-3 h-3 pointer-events-none ${isActive ? 'text-white/60' : 'text-neutral-400'}`} />
   134→
   135→      {open && createPortal(
   136→        <div
   137→          ref={dropRef}
   138→          style={{ position: 'fixed', top: pos.top, left: pos.left, zIndex: 9999 }}
   139→          className="bg-white border border-neutral-100 rounded-2xl shadow-2xl p-4 w-72"
   140→        >
   141→          <div className="flex gap-2 mb-3 pb-3 border-b border-neutral-100">
   142→            <button type="button" onClick={() => { onChange('', ''); setSelecting(null); handleClose(); }}
   143→              className={`flex-1 text-[10px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg transition-colors cursor-pointer ${
   144→                !valueFrom && !valueTo && !selecting ? 'bg-neutral-950 text-white' : 'text-neutral-400 hover:text-neutral-700 hover:bg-neutral-50 border border-neutral-200'
   145→              }`}>
   146→              Все записи
   147→            </button>
   148→            <button type="button" onClick={() => {
   149→                const d = parseDateStr(today) || new Date();
   150→                setViewYear(d.getFullYear()); setViewMonth(d.getMonth());
   151→                onChange(today, today); setSelecting(null); handleClose();
   152→              }}
   153→              className={`flex-1 text-[10px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg transition-colors cursor-pointer ${
   154→                valueFrom === today && valueTo === today ? 'bg-indigo-600 text-white' : 'text-indigo-600 hover:bg-indigo-50 border border-indigo-100'
   155→              }`}>
   156→              Сегодня
   157→            </button>
   158→          </div>
   159→
   160→          <div className="mb-2 text-center text-[10px] font-bold uppercase tracking-widest text-neutral-400 h-4">
   161→            {selecting ? 'Выберите конечную дату' : 'Выберите начальную дату'}
   162→          </div>
   163→
   164→          <div className="flex items-center justify-between mb-3">
   165→            <button type="button" onClick={prevMonth} className="p-1.5 rounded-lg hover:bg-neutral-100 transition-colors cursor-pointer">
   166→              <ChevronLeft className="w-4 h-4 text-neutral-500" />
   167→            </button>
   168→            <span className="text-sm font-bold text-neutral-800">{MONTHS_RU[viewMonth]} {viewYear}</span>
   169→            <button type="button" onClick={nextMonth} className="p-1.5 rounded-lg hover:bg-neutral-100 transition-colors cursor-pointer">
   170→              <ChevronRight className="w-4 h-4 text-neutral-500" />
   171→            </button>
   172→          </div>
   173→
   174→          <div className="grid grid-cols-7 mb-1">
   175→            {DAYS_SHORT.map(d => <div key={d} className="text-center text-[10px] font-bold text-neutral-400 py-1">{d}</div>)}
   176→          </div>
   177→
   178→          <div className="grid grid-cols-7 gap-y-0.5">
   179→            {cells.map((day, i) => {
   180→              if (!day) return <div key={i} />;
   181→              const dateStr = toDateStr(new Date(viewYear, viewMonth, day));
   182→              const ef = rangeFrom < rangeTo ? rangeFrom : rangeTo;
   183→              const et = rangeFrom < rangeTo ? rangeTo   : rangeFrom;
   184→              const isStart   = dateStr === ef && !!ef;
   185→              const isEnd     = dateStr === et && !!et && et !== ef;
   186→              const isInRange = !!ef && !!et && dateStr > ef && dateStr < et;
   187→              const isToday   = today === dateStr;
   188→              return (
   189→                <button key={i} type="button"
   190→                  onClick={() => handleDayClick(dateStr)}
   191→                  onMouseEnter={() => selecting && setHoverDate(dateStr)}
   192→                  onMouseLeave={() => selecting && setHoverDate(null)}
   193→                  className={`text-xs font-medium py-1.5 transition-colors duration-75 cursor-pointer relative ${
   194→                    isStart || isEnd
   195→                      ? 'bg-indigo-600 text-white font-bold rounded-lg'
   196→                      : isInRange
   197→                        ? 'bg-indigo-50 text-indigo-700 rounded-none'
   198→                        : isToday
   199→                          ? 'bg-neutral-100 text-neutral-800 font-bold rounded-lg'
   200→                          : 'hover:bg-neutral-100 text-neutral-700 rounded-lg'
   201→                  }`}
   202→                >
   203→                  {day}
   204→                </button>
   205→              );
   206→            })}
   207→          </div>
   208→        </div>
   209→      , document.body)}
   210→    </div>
   211→  );
   212→}
