   214→/* ══════════════════════════════════════════════
   215→   SingleDatePicker — single date, portal
   216→══════════════════════════════════════════════ */
   217→export function SingleDatePicker({ value, onChange }: { value: string; onChange: (v: string) => void }) {
   218→  const [open, setOpen] = useState(false);
   219→  const btnRef  = useRef<HTMLButtonElement>(null);
   220→  const dropRef = useRef<HTMLDivElement>(null);
   221→  const [pos, setPos]   = useState({ top: 0, left: 0 });
   222→  const today = todayLocal();
   223→  const parsed = parseDateStr(value);
   224→  const [viewYear,  setViewYear]  = useState(parsed ? parsed.getFullYear() : new Date().getFullYear());
   225→  const [viewMonth, setViewMonth] = useState(parsed ? parsed.getMonth()    : new Date().getMonth());
   226→
   227→  const updatePos = () => {
   228→    if (btnRef.current) {
   229→      const r = btnRef.current.getBoundingClientRect();
   230→      setPos({ top: r.bottom + 8, left: r.left });
   231→    }
   232→  };
   233→  const handleOpen = () => { if (!open) updatePos(); setOpen(o => !o); };
   234→
   235→  useEffect(() => {
   236→    if (!open) return;
   237→    function onDown(e: MouseEvent) {
   238→      const t = e.target as Node;
   239→      if (btnRef.current && !btnRef.current.contains(t) && dropRef.current && !dropRef.current.contains(t)) setOpen(false);
   240→    }
   241→    function onScroll() { updatePos(); }
   242→    document.addEventListener('mousedown', onDown);
   243→    window.addEventListener('scroll', onScroll, true);
   244→    return () => { document.removeEventListener('mousedown', onDown); window.removeEventListener('scroll', onScroll, true); };
   245→  }, [open]);
   246→
   247→  useEffect(() => {
   248→    const d = parseDateStr(value);
   249→    if (d) { setViewYear(d.getFullYear()); setViewMonth(d.getMonth()); }
   250→  }, [value]);
   251→
   252→  function prevMonth() { if (viewMonth === 0) { setViewMonth(11); setViewYear(y => y-1); } else setViewMonth(m => m-1); }
   253→  function nextMonth() { if (viewMonth === 11) { setViewMonth(0); setViewYear(y => y+1); } else setViewMonth(m => m+1); }
   254→
   255→  const cells      = buildCells(viewYear, viewMonth);
   256→  const isActive   = !!value;
   257→  const displayLabel = value ? fmtDateShort(value) : 'Выберите дату';
   258→
   259→  return (
   260→    <div className="relative flex items-center">
   261→      <button
   262→        ref={btnRef} type="button" onClick={handleOpen}
   263→        className={`w-full text-xs pl-3 pr-8 py-2.5 border rounded-xl focus:outline-hidden cursor-pointer shadow-3xs transition-all duration-150 flex items-center gap-2 ${
   264→          isActive ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white/80 hover:bg-white border-neutral-200/70 text-neutral-600'
   265→        }`}
   266→      >
   267→        <CalendarDays className={`w-3.5 h-3.5 shrink-0 ${isActive ? 'text-indigo-200' : 'text-neutral-400'}`} />
   268→        <span className={`font-bold truncate ${isActive ? 'text-white' : 'text-neutral-700'}`}>{displayLabel}</span>
   269→      </button>
   270→      <ChevronDown className={`absolute right-2.5 w-3 h-3 pointer-events-none ${isActive ? 'text-white/60' : 'text-neutral-400'}`} />
   271→
   272→      {open && createPortal(
   273→        <div
   274→          ref={dropRef}
   275→          style={{ position: 'fixed', top: pos.top, left: pos.left, zIndex: 9999 }}
   276→          className="bg-white border border-neutral-100 rounded-2xl shadow-2xl p-4 w-72"
   277→        >
   278→          <div className="flex gap-2 mb-3 pb-3 border-b border-neutral-100">
   279→            <button type="button" onClick={() => { onChange(''); setOpen(false); }}
   280→              className={`flex-1 text-[10px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg transition-colors cursor-pointer ${
   281→                !value ? 'bg-neutral-950 text-white' : 'text-neutral-400 hover:text-neutral-700 hover:bg-neutral-50 border border-neutral-200'
   282→              }`}>
   283→              Очистить
   284→            </button>
   285→            <button type="button" onClick={() => {
   286→                onChange(today);
   287→                const d = parseDateStr(today);
   288→                if (d) { setViewYear(d.getFullYear()); setViewMonth(d.getMonth()); }
   289→                setOpen(false);
   290→              }}
   291→              className={`flex-1 text-[10px] font-bold uppercase tracking-widest px-3 py-1.5 rounded-lg transition-colors cursor-pointer ${
   292→                value === today ? 'bg-indigo-600 text-white' : 'text-indigo-600 hover:bg-indigo-50 border border-indigo-100'
   293→              }`}>
   294→              Сегодня
   295→            </button>
   296→          </div>
   297→
   298→          <div className="flex items-center justify-between mb-3">
   299→            <button type="button" onClick={prevMonth} className="p-1.5 rounded-lg hover:bg-neutral-100 transition-colors cursor-pointer"><ChevronLeft className="w-4 h-4 text-neutral-500" /></button>
   300→            <span className="text-sm font-bold text-neutral-800">{MONTHS_RU[viewMonth]} {viewYear}</span>
   301→            <button type="button" onClick={nextMonth} className="p-1.5 rounded-lg hover:bg-neutral-100 transition-colors cursor-pointer"><ChevronRight className="w-4 h-4 text-neutral-500" /></button>
   302→          </div>
   303→
   304→          <div className="grid grid-cols-7 mb-1">
   305→            {DAYS_SHORT.map(d => <div key={d} className="text-center text-[10px] font-bold text-neutral-400 py-1">{d}</div>)}
   306→          </div>
   307→
   308→          <div className="grid grid-cols-7 gap-y-0.5">
   309→            {cells.map((day, i) => {
   310→              if (!day) return <div key={i} />;
   311→              const dateStr    = toDateStr(new Date(viewYear, viewMonth, day));
   312→              const isSelected = String(value).slice(0, 10) === dateStr;
   313→              const isToday    = today === dateStr;
   314→              return (
   315→                <button key={i} type="button"
   316→                  onClick={() => { onChange(dateStr); setOpen(false); }}
   317→                  className={`text-xs font-medium py-1.5 transition-colors duration-75 cursor-pointer rounded-lg ${
   318→                    isSelected ? 'bg-indigo-600 text-white font-bold' : isToday ? 'bg-neutral-100 text-neutral-800 font-bold' : 'hover:bg-neutral-100 text-neutral-700'
   319→                  }`}
   320→                >
   321→                  {day}
   322→                </button>
   323→              );
   324→            })}
   325→          </div>
   326→        </div>
   327→      , document.body)}
   328→    </div>
   329→  );
   330→}
   331→
   332→/* ══════════════════════════════════════════════
   333→   PortalSelect — custom dropdown with portal
   334→   allLabel: label shown for empty/all value
   335→   activeClass: extra classes when value !== allValue
   336→══════════════════════════════════════════════ */
   337→export function PortalSelect({
   338→  value, onChange, options, allLabel = 'Все', allValue = 'all', className = '',
   339→}: {
   340→  value: string;
   341→  onChange: (v: string) => void;
   342→  options: { value: string; label: string }[];
   343→  allLabel?: string;
   344→  allValue?: string;
   345→  className?: string;
   346→}) {
   347→  const [open, setOpen] = useState(false);
   348→  const btnRef  = useRef<HTMLButtonElement>(null);
   349→  const dropRef = useRef<HTMLDivElement>(null);
   350→  const [pos, setPos]   = useState({ top: 0, left: 0, width: 0 });
   351→
   352→  const updatePos = () => {
   353→    if (btnRef.current) {
   354→      const r = btnRef.current.getBoundingClientRect();
   355→      setPos({ top: r.bottom + 6, left: r.left, width: Math.max(r.width, 160) });
   356→    }
   357→  };
   358→  const handleOpen = () => { if (!open) updatePos(); setOpen(o => !o); };
   359→
   360→  useEffect(() => {
   361→    if (!open) return;
   362→    function onDown(e: MouseEvent) {
   363→      const t = e.target as Node;
   364→      if (btnRef.current && !btnRef.current.contains(t) && dropRef.current && !dropRef.current.contains(t)) setOpen(false);
   365→    }
   366→    function onScroll() { updatePos(); }
   367→    document.addEventListener('mousedown', onDown);
   368→    window.addEventListener('scroll', onScroll, true);
   369→    return () => { document.removeEventListener('mousedown', onDown); window.removeEventListener('scroll', onScroll, true); };
   370→  }, [open]);
   371→
   372→  const isActive       = value !== allValue && value !== '';
   373→  const selectedLabel  = isActive ? (options.find(o => o.value === value)?.label ?? value) : allLabel;
   374→
   375→  return (
   376→    <div className={`relative flex items-center ${className}`}>
   377→      <button
   378→        ref={btnRef} type="button" onClick={handleOpen}
   379→        className={`text-[10px] font-bold pl-3 pr-7 py-2 border rounded-xl focus:outline-none cursor-pointer shadow-3xs transition-all duration-150 whitespace-nowrap ${
   380→          isActive ? 'bg-neutral-950 text-white border-neutral-950' : 'bg-white/60 hover:bg-white border-neutral-200/70 text-neutral-600'
   381→        }`}
   382→      >
   383→        {selectedLabel}
   384→      </button>
   385→      <ChevronDown className={`absolute right-2 w-3 h-3 pointer-events-none transition-transform duration-150 ${open ? 'rotate-180' : ''} ${isActive ? 'text-white/60' : 'text-neutral-400'}`} />
   386→
   387→      {open && createPortal(
   388→        <div
   389→          ref={dropRef}
   390→          style={{ position: 'fixed', top: pos.top, left: pos.left, minWidth: pos.width, zIndex: 9999 }}
   391→          className="bg-white border border-neutral-100 rounded-2xl shadow-2xl py-1.5 overflow-hidden"
   392→        >
   393→          <button type="button"
   394→            onClick={() => { onChange(allValue); setOpen(false); }}
   395→            className={`w-full text-left px-4 py-2.5 text-xs transition-colors duration-100 cursor-pointer flex items-center justify-between gap-3 ${
   396→              !isActive ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-neutral-500 font-medium hover:bg-neutral-50'
   397→            }`}
   398→          >
   399→            <span>{allLabel}</span>
   400→            {!isActive && <Check className="w-3.5 h-3.5 text-indigo-500 shrink-0" />}
   401→          </button>
   402→          {options.map(opt => (
   403→            <button key={opt.value} type="button"
   404→              onClick={() => { onChange(opt.value); setOpen(false); }}
   405→              className={`w-full text-left px-4 py-2.5 text-xs transition-colors duration-100 cursor-pointer flex items-center justify-between gap-3 ${
   406→                value === opt.value ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-neutral-700 font-medium hover:bg-neutral-50'
   407→              }`}
   408→            >
   409→              <span>{opt.label}</span>
   410→              {value === opt.value && <Check className="w-3.5 h-3.5 text-indigo-500 shrink-0" />}
   411→            </button>
   412→          ))}
   413→        </div>
   414→      , document.body)}
   415→    </div>
   416→  );
   417→}
