   419→/* ══════════════════════════════════════════════
   420→   FormSelect — portal dropdown for form fields
   421→   (shows placeholder when empty, styled for form)
   422→══════════════════════════════════════════════ */
   423→export function FormSelect({
   424→  value, onChange, options, placeholder = '— Выбрать —',
   425→}: {
   426→  value: string;
   427→  onChange: (v: string) => void;
   428→  options: string[];
   429→  placeholder?: string;
   430→}) {
   431→  const [open, setOpen] = useState(false);
   432→  const btnRef  = useRef<HTMLButtonElement>(null);
   433→  const dropRef = useRef<HTMLDivElement>(null);
   434→  const [pos, setPos]   = useState({ top: 0, left: 0, width: 0 });
